import{_ as n,o as s,c as e,ai as l}from"./chunks/framework.CzqNhXfh.js";const b=JSON.parse('{"title":"分支定界算法","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/branch-and-bound.md","filePath":"or-opt/branch-and-bound.md","lastUpdated":1776756882000}'),r={name:"or-opt/branch-and-bound.md"};function t(p,a,i,o,d,h){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="分支定界算法" tabindex="-1">分支定界算法 <a class="header-anchor" href="#分支定界算法" aria-label="Permalink to &quot;分支定界算法&quot;">​</a></h1><p>分支定界（Branch and Bound, BB）算法是求解整数规划（IP）问题的经典方法。</p><h2 id="算法步骤" tabindex="-1">算法步骤 <a class="header-anchor" href="#算法步骤" aria-label="Permalink to &quot;算法步骤&quot;">​</a></h2><p>用分支定界算法求解 max 的 IP 问题的一般步骤如下（≤ 约束）：</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>求得原问题线性松弛模型的最优解，作为节点 1。</p><h3 id="_2-设置上下界" tabindex="-1">2. 设置上下界 <a class="header-anchor" href="#_2-设置上下界" aria-label="Permalink to &quot;2. 设置上下界&quot;">​</a></h3><p>在节点 1 处：</p><ul><li>将线性松弛的最优解作为 <strong>UB</strong>（上界）</li><li>将线性松弛的解向下圆整获得的解作为 <strong>LB</strong>（下界）</li></ul><h3 id="_3-选择分支变量" tabindex="-1">3. 选择分支变量 <a class="header-anchor" href="#_3-选择分支变量" aria-label="Permalink to &quot;3. 选择分支变量&quot;">​</a></h3><p>选择分数部分最大的小数变量进行分支，构建两个将可行域按照变量的整数限制分割成两个子区域的分支约束：</p><ul><li>构造一个 ≤ 约束</li><li>构造一个 ≥ 约束</li></ul><h3 id="_4-创建分支节点" tabindex="-1">4. 创建分支节点 <a class="header-anchor" href="#_4-创建分支节点" aria-label="Permalink to &quot;4. 创建分支节点&quot;">​</a></h3><p>在 BB tree 里创建两个新的节点：</p><ul><li>一个是对应 ≥ 约束的节点</li><li>另一个是对应 ≤ 约束的节点</li></ul><h3 id="_5-求解子问题" tabindex="-1">5. 求解子问题 <a class="header-anchor" href="#_5-求解子问题" aria-label="Permalink to &quot;5. 求解子问题&quot;">​</a></h3><p>求解这两个新的节点处的线性松弛模型。</p><h3 id="_6-更新上下界与剪枝判断" tabindex="-1">6. 更新上下界与剪枝判断 <a class="header-anchor" href="#_6-更新上下界与剪枝判断" aria-label="Permalink to &quot;6. 更新上下界与剪枝判断&quot;">​</a></h3><ul><li>松弛的解是每个点的 UB</li><li>已经得到的整数解（在任意节点上）是 LB</li><li>根据查明的条件，判断该节点是否已被查明（剪枝）</li></ul><h3 id="_7-最优性判断" tabindex="-1">7. 最优性判断 <a class="header-anchor" href="#_7-最优性判断" aria-label="Permalink to &quot;7. 最优性判断&quot;">​</a></h3><p>当一个节点得到了一个整数解，并且该节点的 LB 大于或者等于其他任何叶子节点的 UB 时（也就是大于或等于全局 UB 时），我们就求得了全局最优整数解。</p><p>如果该节点的解不是整数解，我们就从所有节点中 UB 最大的节点处开始分支。</p><h3 id="_8-迭代" tabindex="-1">8. 迭代 <a class="header-anchor" href="#_8-迭代" aria-label="Permalink to &quot;8. 迭代&quot;">​</a></h3><p>回到步骤（3），继续分支过程，直到找到最优解或所有节点都被查明。</p><hr><h2 id="算法流程图" tabindex="-1">算法流程图 <a class="header-anchor" href="#算法流程图" aria-label="Permalink to &quot;算法流程图&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>求解线性松弛</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>设置初始 UB/LB</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>选择分支变量 → 创建两个子节点（≤ 和 ≥ 约束）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>求解子节点线性松弛</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>更新 UB/LB，判断剪枝条件</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>找到最优整数解？</span></span>
<span class="line"><span>   /        \\</span></span>
<span class="line"><span>  是        否</span></span>
<span class="line"><span>  ↓          ↓</span></span>
<span class="line"><span>结束      选择 UB 最大节点继续分支</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td><strong>UB (Upper Bound)</strong></td><td>上界，由线性松弛解给出</td></tr><tr><td><strong>LB (Lower Bound)</strong></td><td>下界，由找到的整数解给出</td></tr><tr><td><strong>剪枝 (Pruning)</strong></td><td>当节点的 UB ≤ 全局 LB 时，该节点无需再分支</td></tr><tr><td><strong>分数变量</strong></td><td>线性松弛解中取值为非整数的变量</td></tr></tbody></table>`,29)])])}const u=n(r,[["render",t]]);export{b as __pageData,u as default};
